// Normaliza Fechainicio/FechaFin (YYYY-MM-DD) a BA (check-in 14:00 / check-out 10:00)
// Calcula noches/días por diferencia de YMD (no por horas) + horizonte simétrico

function mkBA(ymd, h, m=0, s=0) {
  return `${ymd}T${String(h).padStart(2,'0')}:${String(m).padStart(2,'0')}:${String(s).padStart(2,'0')}-03:00`;
}
function addDaysYMD(ymd, n) {
  const t = new Date(`${ymd}T00:00:00Z`).getTime() + n*86400000;
  const d = new Date(t);
  return `${d.getUTCFullYear()}-${String(d.getUTCMonth()+1).padStart(2,'0')}-${String(d.getUTCDate()).padStart(2,'0')}`;
}
function daysDiffYMD(a, b) { // b - a en días de calendario
  const ta = new Date(`${a}T00:00:00Z`).getTime();
  const tb = new Date(`${b}T00:00:00Z`).getTime();
  return Math.max(0, Math.round((tb - ta)/86400000));
}

const inItem = $input.first().json;
const ymdStart = String(inItem.Fechainicio ?? inItem.FechaInicio ?? inItem.fechainicio ?? inItem.fechaInicio).match(/\d{4}-\d{2}-\d{2}/)?.[0];
const ymdEnd   = String(inItem.FechaFin ?? inItem.Fechafin ?? inItem.fechaFin ?? inItem.fechafin).match(/\d{4}-\d{2}-\d{2}/)?.[0];

if (!ymdStart || !ymdEnd) {
  return [{ json: { ok:false, error:"Fechas faltantes o inválidas (YYYY-MM-DD)." } }];
}

// Horas fijas BA
const fechaInicioBA = mkBA(ymdStart, 14, 0, 0);
const fechaFinBA    = mkBA(ymdEnd,   10, 0, 0);

// ✅ Noches = (días de calendario entre start y end) - 1
const dias   = daysDiffYMD(ymdStart, ymdEnd); // p.ej. 05→10 = 5
const noches = Math.max(1, dias - 1);         // 5 - 1 = 4

// Horizonte simétrico (configurable)
const horizonteDias = Number(inItem.horizonteDias ?? 60);
const horizonteIniYMD = addDaysYMD(ymdStart, -horizonteDias);
const horizonteFinYMD = addDaysYMD(ymdStart,  +horizonteDias);
const horizonteIniBA  = mkBA(horizonteIniYMD, 0, 0, 0);
const horizonteFinBA  = mkBA(horizonteFinYMD, 23, 59, 59);

return [{
  json: {
    ok:true,
    ymdStart, ymdEnd,
    fechaInicioBA, fechaFinBA,
    noches, dias,
    horizonteDias,
    horizonteIniYMD, horizonteFinYMD,
    horizonteIniBA,  // usar en After
    horizonteFinBA   // usar en Before
  }
}];

function ymd(d){ const x=new Date(d); return `${x.getFullYear()}-${String(x.getMonth()+1).padStart(2,'0')}-${String(x.getDate()).padStart(2,'0')}`; }
function addDays(s, n){ return ymd(new Date(new Date(s+'T00:00:00Z').getTime() + n*86400000)); }
function mkBA(s,h,m=0,sec=0){ return `${s}T${String(h).padStart(2,'0')}:${String(m).padStart(2,'0')}:${String(sec).padStart(2,'0')}-03:00`; }
function daysBetween(a,b){ return Math.max(0, Math.round((new Date(b+'T00:00:00Z') - new Date(a+'T00:00:00Z'))/86400000)); }

// Normalización del Code 1
const [normItem] = $items('Code in JavaScript', 0, 0); // <-- cambia nombre si hace falta
const norm = normItem?.json;
if (!norm) return [{ json: { ok:false, error:"No encuentro salida del Code 1." } }];

const noches = Number(norm.noches);
const startRequestedYMD = norm.ymdStart;
const limInf = norm.horizonteIniYMD, limSup = norm.horizonteFinYMD;
const maxSteps = Math.max(1, daysBetween(limInf, limSup));

// Eventos del calendario (horizonte completo)
const evItems = $('Get many events2').all(); // <-- cambia nombre si hace falta

// Días ocupados (timed y all-day; end.date exclusivo)
const busy = new Set();
for (const it of evItems) {
  const e = it.json;
  const sISO = e.start?.dateTime || (e.start?.date ? `${e.start.date}T00:00:00-03:00` : null);
  const eISO = e.end?.dateTime   || (e.end?.date   ? `${e.end.date}T00:00:00-03:00`   : null);
  if (!sISO || !eISO) continue;
  let d = ymd(sISO), endExcl = ymd(eISO);
  while (d < endExcl) { busy.add(d); d = addDays(d, 1); }
}

function isFreeBlock(d0, n){
  let d = d0;
  for (let i=0;i<n;i++){ if (busy.has(d)) return false; d = addDays(d,1); }
  return true;
}

// Si el rango pedido está libre → devolver ese
if (isFreeBlock(startRequestedYMD, noches)) {
  let endYMD = startRequestedYMD; for (let i=0;i<noches;i++) endYMD = addDays(endYMD,1);
  const opcion = {
    startYMD: startRequestedYMD,
    endYMD,
    startBA: mkBA(startRequestedYMD,14,0,0),
    endBA:   mkBA(endYMD,10,0,0),
    noches,
    dias: noches+1
  };
  return [{ json: { disponible:true, opcion, mensaje:`Disponible: ${opcion.startYMD}–${opcion.endYMD}` } }];
}

// Buscar la MÁS CERCANA (empate → preferimos FUTURO)
let mejor = null;
for (let step = 1; step <= maxSteps; step++) {
  const fwdStart = addDays(startRequestedYMD, step);
  if (fwdStart <= limSup && isFreeBlock(fwdStart, noches)) {
    let endYMD = fwdStart; for (let i=0;i<noches;i++) endYMD = addDays(endYMD,1);
    mejor = { startYMD: fwdStart, endYMD, delta: step, dir: 'fwd' };
    break;
  }
  const backStart = addDays(startRequestedYMD, -step);
  if (backStart >= limInf && isFreeBlock(backStart, noches)) {
    let endYMD = backStart; for (let i=0;i<noches;i++) endYMD = addDays(endYMD,1);
    mejor = { startYMD: backStart, endYMD, delta: step, dir: 'back' };
    break;
  }
}

let opcion = null;
if (mejor) {
  opcion = {
    startYMD: mejor.startYMD,
    endYMD:   mejor.endYMD,
    startBA:  mkBA(mejor.startYMD,14,0,0),
    endBA:    mkBA(mejor.endYMD,10,0,0),
    noches,
    dias: noches+1
  };
}

return [{
  json: {
    disponible:false,
    opcion,
    mensaje: opcion
      ? `La opción más cercana disponible es del ${opcion.startYMD} hasta ${opcion.endYMD}`
      : 'No hay opciones dentro del horizonte.'
  }
}];
